import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Student, AttendanceRecord, ClassSession, User, ClassTemplate, Belt } from '../types';
import { StorageService } from '../services/storage';
import { 
  Search, 
  UserCheck, 
  CheckCircle, 
  Plus, 
  ChevronLeft,
  Users,
  QrCode,
  X,
  Zap,
  Monitor,
  Trophy,
  Star,
  Timer,
  RefreshCw,
  Globe,
  Filter,
  AlertTriangle
} from 'lucide-react';
import { BELT_COLORS } from '../constants';

declare const Html5Qrcode: any;

const calculateAge = (birthDate: string) => {
  if (!birthDate) return 0;
  const today = new Date();
  const birth = new Date(birthDate);
  let age = today.getFullYear() - birth.getFullYear();
  const m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
    age--;
  }
  return age;
};

const getGraduationMilestone = (student: Student) => {
  const age = calculateAge(student.birthDate);
  if (age < 16) return null;

  const nextTotal = student.totalClasses + 1;

  if (student.belt === Belt.WHITE) {
    if (nextTotal === 80) return "Elegível para Faixa Azul!";
    if (nextTotal % 20 === 0) return `Marco atingido: ${nextTotal / 20}º Grau!`;
  } else if ([Belt.BLUE, Belt.PURPLE, Belt.BROWN].includes(student.belt)) {
    if (nextTotal === 160) return "Elegível para Troca de Faixa!";
    if (nextTotal % 40 === 0) return `Marco atingido: ${nextTotal / 40}º Grau!`;
  }
  return null;
};

const AttendanceView: React.FC<{ user: User }> = ({ user }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [templates, setTemplates] = useState<ClassTemplate[]>([]);
  const [allClasses, setAllClasses] = useState<ClassSession[]>([]);
  const [currentClass, setCurrentClass] = useState<ClassSession | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);

  const [showAllStudents, setShowAllStudents] = useState(false);

  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isKioskMode, setIsKioskMode] = useState(false);
  const [isFinishModalOpen, setIsFinishModalOpen] = useState(false);
  const [lastScannedStudent, setLastScannedStudent] = useState<Student | null>(null);
  const [graduationMilestone, setGraduationMilestone] = useState<string | null>(null);
  const [recentScans, setRecentScans] = useState<Student[]>([]);

  const [search, setSearch] = useState('');
  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

  const html5QrCodeRef = useRef<any>(null);

  const loadData = () => {
    const loadedStudents = StorageService.getStudents().filter(s => s.status === 'Active');
    const loadedTemplates = StorageService.getTemplates();
    const loadedClasses = StorageService.getClasses();

    setStudents(loadedStudents);
    setTemplates(loadedTemplates);
    setAllClasses(loadedClasses);
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCheckIn = (student: Student) => {
    setCheckedIds(prev => {
      const next = new Set(prev);
      const studentId = student.id;

      if (next.has(studentId)) {
        next.delete(studentId);
      } else {
        next.add(studentId);
      }

      if (currentClass) {
        const updatedClasses: ClassSession[] = StorageService.getClasses().map(c => 
          c.id === currentClass.id ? { ...c, attendanceIds: Array.from(next) as string[] } : c
        );
        StorageService.saveClasses(updatedClasses);
      }
      return next;
    });
  };

  useEffect(() => {
    let isMounted = true;

    if ((isScannerOpen || isKioskMode) && currentClass) {
      const startCamera = async () => {
        await new Promise(resolve => setTimeout(resolve, 300));

        if (!document.getElementById("qr-reader")) return;

        try {
          const html5QrCode = new Html5Qrcode("qr-reader");
          html5QrCodeRef.current = html5QrCode;

          const config = { 
            fps: 15, 
            qrbox: { width: 250, height: 250 },
            aspectRatio: 1.0
          };

          const onScanSuccess = (decodedText: string) => {
            const student = students.find(s => s.id === decodedText);
            if (student) {
              handleCheckIn(student);

              const milestone = getGraduationMilestone(student);
              setLastScannedStudent(student);
              setGraduationMilestone(milestone);
              setRecentScans(prev => {
                const isAlreadyInRecent = prev.some(s => s.id === student.id);
                if (isAlreadyInRecent) return prev;
                return [student, ...prev.slice(0, 5)];
              });

              if (navigator.vibrate) milestone ? navigator.vibrate([100, 50, 200, 50, 300]) : navigator.vibrate(100);

              setTimeout(() => {
                if (isMounted) {
                  setLastScannedStudent(null);
                  setGraduationMilestone(null);
                }
              }, milestone ? 5000 : 2500);
            }
          };

          await html5QrCode.start(
            { facingMode: "environment" }, 
            config, 
            onScanSuccess,
            (errorMessage: string) => { /* ignore logs */ }
          );
        } catch (err) {
          console.error("Erro ao iniciar câmera:", err);
        }
      };

      startCamera();
    }

    return () => {
      isMounted = false;
      if (html5QrCodeRef.current) {
        html5QrCodeRef.current.stop().then(() => {
          html5QrCodeRef.current.clear();
        }).catch((err: any) => console.warn("Erro ao parar scanner:", err));
      }
    };
  }, [isScannerOpen, isKioskMode, currentClass, students]);

  const currentTemplate = useMemo(() => {
    if (!currentClass?.templateId) return null;
    return templates.find(t => t.id === currentClass.templateId);
  }, [currentClass, templates]);

  const filteredStudents = useMemo(() => {
    if (!currentClass) return [];

    let baseList = students;
    if (currentTemplate && !showAllStudents) {
      baseList = students.filter(s => currentTemplate.assignedStudentIds.includes(s.id));
    }

    return baseList
      .filter(s => s.name.toLowerCase().includes(search.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [currentClass, students, search, currentTemplate, showAllStudents]);

  const startClass = (name: string, templateId?: string, duration = 60) => {
    const newClass: ClassSession = {
      id: `class_${Date.now()}`,
      name,
      templateId,
      date: new Date().toISOString(),
      durationMinutes: duration,
      instructorId: user.id,
      attendanceIds: [],
      status: 'In Progress'
    };
    const updated = [newClass, ...allClasses];
    StorageService.saveClasses(updated);
    setAllClasses(updated);
    setCurrentClass(newClass);
    setCheckedIds(new Set());
    setShowAllStudents(!templateId);
  };

  const handleFinishClass = () => {
    if (!currentClass) return;

    const allAttendance = StorageService.getAttendance();
    const date = new Date().toISOString();

    const newRecords: AttendanceRecord[] = Array.from(checkedIds).map((studentId: string) => ({
      id: Math.random().toString(36).substr(2, 9),
      studentId,
      classId: currentClass.id,
      date,
      durationMinutes: currentClass.durationMinutes,
      kimonoTaken: false
    }));

    StorageService.saveAttendance([...allAttendance, ...newRecords]);

    const updatedClasses: ClassSession[] = StorageService.getClasses().map(c => 
      c.id === currentClass.id ? { ...c, attendanceIds: Array.from(checkedIds) as string[], status: 'Finalized' } : c
    );
    StorageService.saveClasses(updatedClasses);
    setAllClasses(updatedClasses);

    const allStudents = StorageService.getStudents();
    const updatedStudents = allStudents.map(s => {
      if (checkedIds.has(s.id)) {
        return {
          ...s,
          totalClasses: s.totalClasses + 1,
          totalHours: s.totalHours + (currentClass.durationMinutes / 60),
          lastAttendance: date,
          absentCount: 0
        };
      } else if (s.status === 'Active') {
        return {
          ...s,
          absentCount: s.absentCount + 1
        };
      }
      return s;
    });
    StorageService.saveStudents(updatedStudents);

    setShowSuccess(true);
    setCheckedIds(new Set());
    setCurrentClass(null);
    setIsKioskMode(false);
    setIsFinishModalOpen(false);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  if (!currentClass) {
    return (
      <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-300 pb-10">
        <header>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Seleção de Treino</h1>
          <p className="text-slate-500 font-medium">Escolha uma turma para abrir a chamada.</p>
        </header>

        {showSuccess && (
          <div className="bg-green-100 border border-green-200 text-green-700 px-5 py-4 rounded-[24px] flex items-center gap-3 animate-bounce">
            <CheckCircle size={24} />
            <span className="font-bold">Presenças computadas com sucesso! OSS.</span>
          </div>
        )}

        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <button 
              onClick={() => startClass('Chamada Geral', undefined, 60)} 
              className="col-span-full bg-gradient-to-br from-indigo-600 to-indigo-800 p-6 rounded-[32px] text-white shadow-xl shadow-indigo-200 text-left hover:scale-[1.02] transition-all group"
            >
              <div className="bg-white/20 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
                <Globe size={24} />
              </div>
              <h4 className="font-black text-xl leading-tight">Chamada Geral</h4>
              <p className="text-indigo-100 text-sm mt-1 font-medium">Listar todos os alunos da academia</p>
            </button>

            <h3 className="col-span-full text-xs font-black text-slate-400 uppercase tracking-widest px-1 mt-4">Turmas Registradas</h3>

            {templates.map(t => (
              <button key={t.id} onClick={() => startClass(t.name, t.id, t.durationMinutes)} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm text-left hover:border-indigo-400 hover:shadow-md transition-all group">
                <div className="bg-indigo-50 w-12 h-12 rounded-2xl flex items-center justify-center text-indigo-600 mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                  <Users size={24} />
                </div>
                <h4 className="font-bold text-slate-800 leading-tight mb-1">{t.name}</h4>
                <p className="text-xs text-slate-400 font-medium">{t.durationMinutes} minutos</p>
              </button>
            ))}

            <button onClick={() => startClass('Aula Avulsa')} className="bg-slate-50 p-6 rounded-[32px] border border-dashed border-slate-300 text-left hover:bg-slate-100 transition-all flex flex-col justify-center">
              <Plus size={24} className="text-slate-400 mb-4" />
              <h4 className="font-bold text-slate-500 italic">Aula Avulsa</h4>
              <p className="text-[10px] text-slate-400 uppercase font-black tracking-tighter mt-1">Manual</p>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto space-y-6 pb-32 animate-in fade-in duration-300">
      <header className="sticky top-0 bg-slate-50 pt-2 z-10 space-y-4 pb-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setCurrentClass(null)} 
              className="bg-white text-slate-600 p-3 rounded-2xl border border-slate-100 shadow-sm hover:bg-slate-100 transition-colors flex items-center gap-2"
            >
              <ChevronLeft size={20} />
              <span className="font-bold text-xs">Trocar</span>
            </button>
            <div>
              <div className="flex items-center gap-2">
                <h1 className="text-lg font-black text-slate-800 leading-tight truncate max-w-[150px]">{currentClass.name}</h1>
                <div className="w-2 h-2 bg-amber-500 rounded-full animate-pulse" />
              </div>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{checkedIds.size} No Tatame</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setIsKioskMode(true)} className="flex items-center gap-2 bg-indigo-50 text-indigo-600 px-4 py-3 rounded-2xl font-bold text-xs border border-indigo-100 shadow-sm"><Monitor size={18} /> Totem</button>
            <button onClick={() => setIsScannerOpen(true)} className="bg-slate-900 text-white p-3 rounded-2xl shadow-lg hover:bg-slate-800"><QrCode size={20} /></button>
          </div>
        </div>

        <div className="space-y-3">
          {currentClass.templateId && (
            <div className="flex bg-slate-200/50 p-1 rounded-2xl">
              <button 
                onClick={() => setShowAllStudents(false)}
                className={`flex-1 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${!showAllStudents ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <Users size={14} /> Desta Turma
              </button>
              <button 
                onClick={() => setShowAllStudents(true)}
                className={`flex-1 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${showAllStudents ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <Globe size={14} /> Todos Alunos
              </button>
            </div>
          )}

          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Buscar aluno para entrada..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full bg-white border border-slate-200 rounded-2xl pl-12 pr-4 py-4 outline-none shadow-sm focus:ring-2 focus:ring-indigo-500" />
          </div>
        </div>
      </header>

      <div className="space-y-2">
        {filteredStudents.length > 0 ? filteredStudents.map(student => {
          const isChecked = checkedIds.has(student.id);
          const isGuest = currentTemplate && !currentTemplate.assignedStudentIds.includes(student.id);

          return (
            <div key={student.id} onClick={() => handleCheckIn(student)}
              className={`flex items-center justify-between p-4 rounded-[28px] border transition-all cursor-pointer ${isChecked ? 'bg-green-50 border-green-200 ring-1 ring-green-100' : 'bg-white border-slate-100 hover:border-slate-300'}`}>
              <div className="flex items-center gap-4">
                <div className="relative">
                  {student.photo ? <img src={student.photo} className="w-12 h-12 rounded-2xl object-cover border-2 border-white shadow-sm" /> : <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-sm ${BELT_COLORS[student.belt].split(' ')[0]}`}>{student.name.charAt(0)}</div>}
                  <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${BELT_COLORS[student.belt].split(' ')[0]}`} />
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <h4 className={`font-bold text-sm ${isChecked ? 'text-green-800' : 'text-slate-800'}`}>{student.name}</h4>
                    {isGuest && <span className="text-[8px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded-full font-black uppercase">Visitante</span>}
                  </div>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{student.belt} • {student.totalClasses} aulas</p>
                </div>
              </div>
              <div className={`w-10 h-10 rounded-2xl border-2 flex items-center justify-center transition-all ${isChecked ? 'bg-green-600 border-green-600 shadow-md shadow-green-200' : 'border-slate-100 bg-slate-50'}`}>
                {isChecked ? <UserCheck size={20} className="text-white" /> : <Plus size={18} className="text-slate-300" />}
              </div>
            </div>
          );
        }) : (
          <div className="py-20 text-center bg-white rounded-[32px] border border-dashed border-slate-200 text-slate-400">
            <Users size={40} className="mx-auto mb-4 opacity-10" />
            <p className="text-sm font-medium">Nenhum aluno encontrado.</p>
          </div>
        )}
      </div>

      <div className="fixed bottom-20 left-4 right-4 md:relative md:bottom-0 md:left-0 md:right-0 z-20">
        <div className="bg-white p-4 rounded-[40px] shadow-2xl border border-slate-100 flex flex-col gap-3">
          <div className="flex items-center justify-between px-2">
            <div className="flex items-center gap-2">
              <Timer size={18} className="text-slate-400" />
              <span className="text-sm font-bold text-slate-600">Treino Aberto</span>
            </div>
            <button onClick={() => setCurrentClass(null)} className="text-xs font-black text-indigo-600 uppercase flex items-center gap-1 hover:underline">
              <RefreshCw size={12} /> Selecionar outra turma
            </button>
          </div>
          <button 
            onClick={() => setIsFinishModalOpen(true)} 
            className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-5 rounded-[30px] shadow-xl transition-all flex items-center justify-center gap-3 active:scale-95"
          >
            <X size={24} />
            ENCERRAR PRESENÇA
          </button>
        </div>
      </div>

      {/* Modal de Confirmação de Encerramento */}
      {isFinishModalOpen && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[40px] p-8 animate-in zoom-in duration-300 shadow-2xl text-center">
            <div className="bg-red-100 w-20 h-20 rounded-full flex items-center justify-center text-red-600 mx-auto mb-6">
              <AlertTriangle size={40} />
            </div>
            <h2 className="text-2xl font-black text-slate-800 mb-2">Encerrar Chamada?</h2>
            <p className="text-sm text-slate-500 font-medium mb-8 leading-relaxed">
              {checkedIds.size === 0 
                ? "Nenhum aluno registrado no tatame. Deseja realmente encerrar a aula sem computar presenças?"
                : `Deseja finalizar o treino e computar presença para os ${checkedIds.size} atletas no tatame?`}
            </p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={handleFinishClass}
                className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-5 rounded-3xl shadow-xl shadow-red-600/20 transition-all active:scale-95"
              >
                Sim, Encerrar Agora
              </button>
              <button 
                onClick={() => setIsFinishModalOpen(false)}
                className="w-full bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold py-5 rounded-3xl transition-all"
              >
                Continuar Chamada
              </button>
            </div>
          </div>
        </div>
      )}

      {(isScannerOpen || isKioskMode) && (
        <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col md:flex-row animate-in fade-in duration-500 overflow-hidden">
          <div className="flex-[3] relative flex flex-col">
            <div className="absolute top-8 left-8 z-20 flex flex-col gap-4">
              <div className="bg-white/10 backdrop-blur-md border border-white/20 p-5 rounded-3xl text-white">
                <h2 className="text-2xl font-black italic flex items-center gap-3 tracking-tighter"><Zap size={24} className="fill-white" /> ENTRADA LIBERADA</h2>
                <p className="text-white/60 text-sm font-medium">{currentClass.name}</p>
              </div>
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-4 rounded-3xl text-white shadow-xl shadow-indigo-600/20">
                  <p className="text-white/40 text-[10px] font-black uppercase tracking-widest leading-none mb-1">Presentes</p>
                  <p className="text-3xl font-black leading-none">{checkedIds.size}</p>
                </div>
              </div>
            </div>

            <div className="flex-1 bg-black flex items-center justify-center relative overflow-hidden">
              <div id="qr-reader" className="w-full h-full [&>video]:object-cover"></div>

              <div className="absolute border-4 border-white/20 w-72 h-72 rounded-[60px] pointer-events-none z-10">
                <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-indigo-500 -mt-1 -ml-1 rounded-tl-[20px]" />
                <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-indigo-500 -mt-1 -mr-1 rounded-tr-[20px]" />
                <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-indigo-500 -mb-1 -ml-1 rounded-bl-[20px]" />
                <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-indigo-500 -mb-1 -mr-1 rounded-br-[20px]" />
              </div>

              {lastScannedStudent && (
                <div className={`absolute inset-0 flex flex-col items-center justify-center p-8 z-30 animate-in zoom-in duration-300 ${graduationMilestone ? 'bg-amber-500/95' : 'bg-indigo-600/95'}`}>
                  <div className="bg-white p-10 rounded-[60px] shadow-2xl flex flex-col items-center text-center max-w-sm w-full">
                    {graduationMilestone ? (
                      <div className="bg-amber-100 text-amber-600 p-8 rounded-full mb-6 animate-bounce border-4 border-amber-200"><Trophy size={100} /></div>
                    ) : (
                      <div className="bg-green-100 text-green-600 p-8 rounded-full mb-6"><CheckCircle size={100} /></div>
                    )}
                    <p className="text-slate-400 font-black uppercase tracking-[0.3em] text-xs mb-2">BEM-VINDO</p>
                    <div className="mb-4">
                      {lastScannedStudent.photo ? <img src={lastScannedStudent.photo} className="w-40 h-40 rounded-[60px] border-4 border-slate-50 shadow-lg object-cover" /> : <div className={`w-32 h-32 rounded-[40px] flex items-center justify-center text-white font-black text-4xl shadow-lg ${BELT_COLORS[lastScannedStudent.belt].split(' ')[0]}`}>{lastScannedStudent.name.charAt(0)}</div>}
                    </div>
                    <h2 className="text-4xl font-black text-slate-900 leading-tight mb-2">{lastScannedStudent.name.split(' ')[0]}</h2>
                    <div className={`px-6 py-2 rounded-2xl font-black text-sm uppercase mb-4 tracking-widest ${BELT_COLORS[lastScannedStudent.belt]}`}>{lastScannedStudent.belt}</div>
                    {graduationMilestone && <p className="text-amber-600 font-black text-2xl mb-6 flex items-center gap-2"><Star size={24} fill="currentColor" /> {graduationMilestone}</p>}
                    <p className="text-6xl font-black text-indigo-600 italic">OSS!</p>
                  </div>
                </div>
              )}
            </div>
          </div>
          <div className="flex-1 bg-slate-900 p-8 flex flex-col border-l border-white/5">
            <h3 className="text-white/40 font-black uppercase tracking-widest text-xs mb-8 flex items-center gap-2">
              <Users size={16} /> Tatame Agora
            </h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 custom-scrollbar">
              {recentScans.map((s, idx) => (
                <div key={`${s.id}-${idx}`} className="bg-white/5 border border-white/10 p-4 rounded-3xl flex items-center gap-4 animate-in slide-in-from-right duration-300">
                  {s.photo ? <img src={s.photo} className="w-12 h-12 rounded-2xl object-cover" /> : <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-xs ${BELT_COLORS[s.belt].split(' ')[0]}`}>{s.name.charAt(0)}</div>}
                  <div className="overflow-hidden text-left">
                    <p className="text-white font-bold leading-tight truncate">{s.name}</p>
                    <p className="text-white/40 text-[10px] uppercase font-black tracking-widest mt-0.5">{s.belt}</p>
                  </div>
                  <div className="ml-auto bg-green-500/20 text-green-500 p-2 rounded-full"><CheckCircle size={16} /></div>
                </div>
              ))}
              {recentScans.length === 0 && <div className="h-full flex flex-col items-center justify-center text-white/10"><Users size={48} className="mb-4" /><p className="font-bold">Aguardando...</p></div>}
            </div>
            <div className="mt-auto pt-8 border-t border-white/5 space-y-3">
