                          ))}
                        </div>
                        <button onClick={() => setEditingStudent({...editingStudent, stripes: Math.min(4, (editingStudent.stripes || 0) + 1)})}><PlusIcon size={18} /></button>
                      </div>
                    </div>

                    <div>
                      <label className="block text-[10px] font-bold text-slate-400 uppercase ml-1 mb-2 flex items-center gap-1">
