import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Student, AttendanceRecord, ClassSession, User, ClassTemplate, Belt } from '../types';
import { StorageService } from '../services/storage';
import { 
  Search, 
  UserCheck, 
  CheckCircle, 
  Plus, 
  ChevronLeft,
  Users,
  QrCode,
  X,
  Zap,
  Monitor,
  Trophy,
  Star,
  Timer,
  RefreshCw,
  Globe,
  Filter,
  AlertTriangle,
  Loader2
} from 'lucide-react';
import { BELT_COLORS } from '../constants';

declare const Html5Qrcode: any;

const calculateAge = (birthDate: string) => {
  if (!birthDate) return 0;
  const today = new Date();
  const birth = new Date(birthDate);
  let age = today.getFullYear() - birth.getFullYear();
  const m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
    age--;
  }
  return age;
};

const getGraduationMilestone = (student: Student) => {
  const age = calculateAge(student.birthDate);
  if (age < 16) return null;

  const nextTotal = student.totalClasses + 1;

  if (student.belt === Belt.WHITE) {
    if (nextTotal === 80) return "Elegível para Faixa Azul!";
    if (nextTotal % 20 === 0) return `Marco atingido: ${nextTotal / 20}º Grau!`;
  } else if ([Belt.BLUE, Belt.PURPLE, Belt.BROWN].includes(student.belt)) {
    if (nextTotal === 160) return "Elegível para Troca de Faixa!";
    if (nextTotal % 40 === 0) return `Marco atingido: ${nextTotal / 40}º Grau!`;
  }
  return null;
};

const AttendanceView: React.FC<{ user: User }> = ({ user }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [templates, setTemplates] = useState<ClassTemplate[]>([]);
  const [allClasses, setAllClasses] = useState<ClassSession[]>([]);
  const [currentClass, setCurrentClass] = useState<ClassSession | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const [showAllStudents, setShowAllStudents] = useState(false);

  const [isScannerOpen, setIsScannerOpen] = useState(false);
  const [isKioskMode, setIsKioskMode] = useState(false);
  const [isFinishModalOpen, setIsFinishModalOpen] = useState(false);
  const [lastScannedStudent, setLastScannedStudent] = useState<Student | null>(null);
  const [graduationMilestone, setGraduationMilestone] = useState<string | null>(null);
  const [recentScans, setRecentScans] = useState<Student[]>([]);

  const [search, setSearch] = useState('');
  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

  const html5QrCodeRef = useRef<any>(null);

  const loadData = () => {
    const loadedStudents = StorageService.getStudents().filter(s => s.status === 'Active');
    const loadedTemplates = StorageService.getTemplates();
    const loadedClasses = StorageService.getClasses();

    setStudents(loadedStudents);
    setTemplates(loadedTemplates);
    setAllClasses(loadedClasses);
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleCheckIn = (student: Student) => {
    setCheckedIds(prev => {
      const next = new Set(prev);
      const studentId = student.id;

      if (next.has(studentId)) {
        next.delete(studentId);
      } else {
        next.add(studentId);
      }

      if (currentClass) {
        const updatedClasses: ClassSession[] = StorageService.getClasses().map(c => 
          c.id === currentClass.id ? { ...c, attendanceIds: Array.from(next) as string[] } : c
        );
        StorageService.saveClasses(updatedClasses);
      }
      return next;
    });
  };

  const stopScanner = async () => {
    if (html5QrCodeRef.current && html5QrCodeRef.current.isScanning) {
      try {
        await html5QrCodeRef.current.stop();
        await html5QrCodeRef.current.clear();
        html5QrCodeRef.current = null;
      } catch (err) {
        console.warn("Erro ao parar scanner:", err);
      }
    }
  };

  useEffect(() => {
    let isMounted = true;

    if ((isScannerOpen || isKioskMode) && currentClass) {
      const startCamera = async () => {
        // Pequeno atraso para garantir que o DOM renderizou o elemento #qr-reader
        await new Promise(resolve => setTimeout(resolve, 500));

        const qrElement = document.getElementById("qr-reader");
        if (!qrElement) return;

        try {
          const html5QrCode = new Html5Qrcode("qr-reader");
          html5QrCodeRef.current = html5QrCode;

          const config = { 
            fps: 15, 
            qrbox: { width: 250, height: 250 },
            aspectRatio: 1.0
          };

          const onScanSuccess = (decodedText: string) => {
            const student = students.find(s => s.id === decodedText);
            if (student) {
              handleCheckIn(student);

              const milestone = getGraduationMilestone(student);
              setLastScannedStudent(student);
              setGraduationMilestone(milestone);
              setRecentScans(prev => {
                const isAlreadyInRecent = prev.some(s => s.id === student.id);
                if (isAlreadyInRecent) return prev;
                return [student, ...prev.slice(0, 5)];
              });

              if (navigator.vibrate) milestone ? navigator.vibrate([100, 50, 200, 50, 300]) : navigator.vibrate(100);

              setTimeout(() => {
                if (isMounted) {
                  setLastScannedStudent(null);
                  setGraduationMilestone(null);
                }
              }, milestone ? 5000 : 2500);
            }
          };

          await html5QrCode.start(
            { facingMode: "environment" }, 
            config, 
            onScanSuccess,
            () => {} // Mudo para evitar logs excessivos
          );
        } catch (err) {
          console.error("Erro ao iniciar câmera:", err);
        }
      };

      startCamera();
    }

    return () => {
      isMounted = false;
      stopScanner();
    };
  }, [isScannerOpen, isKioskMode, currentClass, students]);

  const currentTemplate = useMemo(() => {
    if (!currentClass?.templateId) return null;
    return templates.find(t => t.id === currentClass.templateId);
  }, [currentClass, templates]);

  const filteredStudents = useMemo(() => {
    if (!currentClass) return [];

    let baseList = students;
    if (currentTemplate && !showAllStudents) {
      baseList = students.filter(s => currentTemplate.assignedStudentIds.includes(s.id));
    }

    return baseList
      .filter(s => s.name.toLowerCase().includes(search.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [currentClass, students, search, currentTemplate, showAllStudents]);

  const startClass = (name: string, templateId?: string, duration = 60) => {
    const newClass: ClassSession = {
      id: `class_${Date.now()}`,
      name,
      templateId,
      date: new Date().toISOString(),
      durationMinutes: duration,
      instructorId: user.id,
      attendanceIds: [],
      status: 'In Progress'
    };
    const updated = [newClass, ...allClasses];
    StorageService.saveClasses(updated);
    setAllClasses(updated);
    setCurrentClass(newClass);
    setCheckedIds(new Set());
    setShowAllStudents(!templateId);
  };

  const handleFinishClass = async () => {
    if (!currentClass || isProcessing) return;
    setIsProcessing(true);

    try {
      // 1. PRIMEIRO: Parar a câmera antes de mudar estados visuais (CRUCIAL PARA MOBILE)
      await stopScanner();
      setIsScannerOpen(false);
      setIsKioskMode(false);

      // Pequena pausa para o hardware processar a liberação
      await new Promise(resolve => setTimeout(resolve, 300));

      const allAttendance = StorageService.getAttendance();
      const date = new Date().toISOString();

      const newRecords: AttendanceRecord[] = Array.from(checkedIds).map((studentId: string) => ({
        id: Math.random().toString(36).substr(2, 9),
        studentId,
        classId: currentClass.id,
        date,
        durationMinutes: currentClass.durationMinutes,
        kimonoTaken: false
      }));

      StorageService.saveAttendance([...allAttendance, ...newRecords]);

      const updatedClasses: ClassSession[] = StorageService.getClasses().map(c => 
        c.id === currentClass.id ? { ...c, attendanceIds: Array.from(checkedIds) as string[], status: 'Finalized' } : c
      );
      StorageService.saveClasses(updatedClasses);
      setAllClasses(updatedClasses);

      const allStudents = StorageService.getStudents();
      const updatedStudents = allStudents.map(s => {
        if (checkedIds.has(s.id)) {
          return {
            ...s,
            totalClasses: s.totalClasses + 1,
            totalHours: s.totalHours + (currentClass.durationMinutes / 60),
            lastAttendance: date,
            absentCount: 0
          };
        } else if (s.status === 'Active') {
          return {
            ...s,
            absentCount: (s.absentCount || 0) + 1
          };
        }
        return s;
      });
      StorageService.saveStudents(updatedStudents);

      setShowSuccess(true);
      setCheckedIds(new Set());
      setCurrentClass(null);
      setIsFinishModalOpen(false);
      setTimeout(() => setShowSuccess(false), 3000);
    } catch (error) {
      console.error("Erro ao encerrar aula:", error);
      alert("Houve um erro ao salvar as presenças. Verifique sua conexão ou espaço de armazenamento.");
    } finally {
      setIsProcessing(false);
    }
  };

  if (!currentClass) {
    return (
      <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-300 pb-10">
        <header>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Seleção de Treino</h1>
          <p className="text-slate-500 font-medium">Escolha uma turma para abrir a chamada.</p>
        </header>

        {showSuccess && (
          <div className="bg-green-100 border border-green-200 text-green-700 px-5 py-4 rounded-[24px] flex items-center gap-3 animate-bounce">
            <CheckCircle size={24} />
            <span className="font-bold">Presenças computadas com sucesso! OSS.</span>
          </div>
        )}

        <div className="space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <button 
              onClick={() => startClass('Chamada Geral', undefined, 60)} 
              className="col-span-full bg-gradient-to-br from-indigo-600 to-indigo-800 p-6 rounded-[32px] text-white shadow-xl shadow-indigo-200 text-left hover:scale-[1.02] transition-all group"
            >
              <div className="bg-white/20 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
                <Globe size={24} />
              </div>
              <h4 className="font-black text-xl leading-tight">Chamada Geral</h4>
              <p className="text-indigo-100 text-sm mt-1 font-medium">Listar todos os alunos da academia</p>
            </button>

            <h3 className="col-span-full text-xs font-black text-slate-400 uppercase tracking-widest px-1 mt-4">Turmas Registradas</h3>

            {templates.map(t => (
              <button key={t.id} onClick={() => startClass(t.name, t.id, t.durationMinutes)} className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm text-left hover:border-indigo-400 hover:shadow-md transition-all group">
                <div className="bg-indigo-50 w-12 h-12 rounded-2xl flex items-center justify-center text-indigo-600 mb-4 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                  <Users size={24} />
                </div>
                <h4 className="font-bold text-slate-800 leading-tight mb-1">{t.name}</h4>
                <p className="text-xs text-slate-400 font-medium">{t.durationMinutes} minutos</p>
              </button>
            ))}

            <button onClick={() => startClass('Aula Avulsa')} className="bg-slate-50 p-6 rounded-[32px] border border-dashed border-slate-300 text-left hover:bg-slate-100 transition-all flex flex-col justify-center">
              <Plus size={24} className="text-slate-400 mb-4" />
              <h4 className="font-bold text-slate-500 italic">Aula Avulsa</h4>
              <p className="text-[10px] text-slate-400 uppercase font-black tracking-tighter mt-1">Manual</p>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto space-y-6 pb-32 animate-in fade-in duration-300">
      <header className="sticky top-0 bg-slate-50 pt-2 z-10 space-y-4 pb-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button 
              onClick={() => setCurrentClass(null)} 
              className="bg-white text-slate-600 p-3 rounded-2xl border border-slate-100 shadow-sm hover:bg-slate-100 transition-colors flex items-center gap-2"
            >
              <ChevronLeft size={20} />
              <span className="font-bold text-xs">Trocar</span>
            </button>
            <div>
              <div className="flex items-center gap-2">
                <h1 className="text-lg font-black text-slate-800 leading-tight truncate max-w-[150px]">{currentClass.name}</h1>
                <div className="w-2 h-2 bg-amber-500 rounded-full animate-pulse" />
              </div>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{checkedIds.size} No Tatame</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setIsKioskMode(true)} className="flex items-center gap-2 bg-indigo-50 text-indigo-600 px-4 py-3 rounded-2xl font-bold text-xs border border-indigo-100 shadow-sm"><Monitor size={18} /> Totem</button>
            <button onClick={() => setIsScannerOpen(true)} className="bg-slate-900 text-white p-3 rounded-2xl shadow-lg hover:bg-slate-800"><QrCode size={20} /></button>
          </div>
        </div>

        <div className="space-y-3">
          {currentClass.templateId && (
            <div className="flex bg-slate-200/50 p-1 rounded-2xl">
              <button 
                onClick={() => setShowAllStudents(false)}
                className={`flex-1 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${!showAllStudents ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <Users size={14} /> Desta Turma
              </button>
              <button 
                onClick={() => setShowAllStudents(true)}
                className={`flex-1 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${showAllStudents ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <Globe size={14} /> Todos Alunos
              </button>
            </div>
          )}

          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input type="text" placeholder="Buscar aluno para entrada..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full bg-white border border-slate-200 rounded-2xl pl-12 pr-4 py-4 outline-none shadow-sm focus:ring-2 focus:ring-indigo-500" />
          </div>
