        </div>
      </div>

      {/* Modal de Confirmação de Encerramento */}
      {isFinishModalOpen && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[40px] p-8 animate-in zoom-in duration-300 shadow-2xl text-center">
            <div className="bg-red-100 w-20 h-20 rounded-full flex items-center justify-center text-red-600 mx-auto mb-6">
              <AlertTriangle size={40} />
            </div>
            <h2 className="text-2xl font-black text-slate-800 mb-2">Encerrar Chamada?</h2>
            <p className="text-sm text-slate-500 font-medium mb-8 leading-relaxed">
              {checkedIds.size === 0 
                ? "Nenhum aluno registrado no tatame. Deseja realmente encerrar a aula sem computar presenças?"
                : `Deseja finalizar o treino e computar presença para os ${checkedIds.size} atletas no tatame?`}
            </p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={handleFinishClass}
                disabled={isProcessing}
                className="w-full bg-red-600 hover:bg-red-700 disabled:bg-slate-400 text-white font-black py-5 rounded-3xl shadow-xl shadow-red-600/20 transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                {isProcessing && <Loader2 size={18} className="animate-spin" />}
