      {(isScannerOpen || isKioskMode) && (
        <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col md:flex-row animate-in fade-in duration-500 overflow-hidden">
          <div className="flex-[3] relative flex flex-col">
            <div className="absolute top-8 left-8 z-20 flex flex-col gap-4">
              <div className="bg-white/10 backdrop-blur-md border border-white/20 p-5 rounded-3xl text-white">
                <h2 className="text-2xl font-black italic flex items-center gap-3 tracking-tighter"><Zap size={24} className="fill-white" /> ENTRADA LIBERADA</h2>
                <p className="text-white/60 text-sm font-medium">{currentClass.name}</p>
              </div>
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-4 rounded-3xl text-white shadow-xl shadow-indigo-600/20">
                  <p className="text-white/40 text-[10px] font-black uppercase tracking-widest leading-none mb-1">Presentes</p>
                  <p className="text-3xl font-black leading-none">{checkedIds.size}</p>
                </div>
              </div>
            </div>

            <div className="flex-1 bg-black flex items-center justify-center relative overflow-hidden">
              <div id="qr-reader" className="w-full h-full [&>video]:object-cover"></div>

              <div className="absolute border-4 border-white/20 w-72 h-72 rounded-[60px] pointer-events-none z-10">
                <div className="absolute top-0 left-0 w-12 h-12 border-t-4 border-l-4 border-indigo-500 -mt-1 -ml-1 rounded-tl-[20px]" />
                <div className="absolute top-0 right-0 w-12 h-12 border-t-4 border-r-4 border-indigo-500 -mt-1 -mr-1 rounded-tr-[20px]" />
                <div className="absolute bottom-0 left-0 w-12 h-12 border-b-4 border-l-4 border-indigo-500 -mb-1 -ml-1 rounded-bl-[20px]" />
                <div className="absolute bottom-0 right-0 w-12 h-12 border-b-4 border-r-4 border-indigo-500 -mb-1 -mr-1 rounded-br-[20px]" />
              </div>

              {lastScannedStudent && (
                <div className={`absolute inset-0 flex flex-col items-center justify-center p-8 z-30 animate-in zoom-in duration-300 ${graduationMilestone ? 'bg-amber-500/95' : 'bg-indigo-600/95'}`}>
                  <div className="bg-white p-10 rounded-[60px] shadow-2xl flex flex-col items-center text-center max-w-sm w-full">
                    {graduationMilestone ? (
                      <div className="bg-amber-100 text-amber-600 p-8 rounded-full mb-6 animate-bounce border-4 border-amber-200"><Trophy size={100} /></div>
                    ) : (
                      <div className="bg-green-100 text-green-600 p-8 rounded-full mb-6"><CheckCircle size={100} /></div>
                    )}
                    <p className="text-slate-400 font-black uppercase tracking-[0.3em] text-xs mb-2">BEM-VINDO</p>
                    <div className="mb-4">
                      {lastScannedStudent.photo ? <img src={lastScannedStudent.photo} className="w-40 h-40 rounded-[60px] border-4 border-slate-50 shadow-lg object-cover" /> : <div className={`w-32 h-32 rounded-[40px] flex items-center justify-center text-white font-black text-4xl shadow-lg ${BELT_COLORS[lastScannedStudent.belt].split(' ')[0]}`}>{lastScannedStudent.name.charAt(0)}</div>}
                    </div>
                    <h2 className="text-4xl font-black text-slate-900 leading-tight mb-2">{lastScannedStudent.name.split(' ')[0]}</h2>
                    <div className={`px-6 py-2 rounded-2xl font-black text-sm uppercase mb-4 tracking-widest ${BELT_COLORS[lastScannedStudent.belt]}`}>{lastScannedStudent.belt}</div>
                    {graduationMilestone && <p className="text-amber-600 font-black text-2xl mb-6 flex items-center gap-2"><Star size={24} fill="currentColor" /> {graduationMilestone}</p>}
                    <p className="text-6xl font-black text-indigo-600 italic">OSS!</p>
                  </div>
                </div>
              )}
            </div>
          </div>
          <div className="flex-1 bg-slate-900 p-8 flex flex-col border-l border-white/5">
            <h3 className="text-white/40 font-black uppercase tracking-widest text-xs mb-8 flex items-center gap-2">
              <Users size={16} /> Tatame Agora
            </h3>
            <div className="flex-1 space-y-4 overflow-y-auto pr-2 custom-scrollbar">
              {recentScans.map((s, idx) => (
                <div key={`${s.id}-${idx}`} className="bg-white/5 border border-white/10 p-4 rounded-3xl flex items-center gap-4 animate-in slide-in-from-right duration-300">
                  {s.photo ? <img src={s.photo} className="w-12 h-12 rounded-2xl object-cover" /> : <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold text-xs ${BELT_COLORS[s.belt].split(' ')[0]}`}>{s.name.charAt(0)}</div>}
                  <div className="overflow-hidden text-left">
                    <p className="text-white font-bold leading-tight truncate">{s.name}</p>
                    <p className="text-white/40 text-[10px] uppercase font-black tracking-widest mt-0.5">{s.belt}</p>
                  </div>
                  <div className="ml-auto bg-green-500/20 text-green-500 p-2 rounded-full"><CheckCircle size={16} /></div>
                </div>
              ))}
              {recentScans.length === 0 && <div className="h-full flex flex-col items-center justify-center text-white/10"><Users size={48} className="mb-4" /><p className="font-bold">Aguardando...</p></div>}
            </div>
            <div className="mt-auto pt-8 border-t border-white/5 space-y-3">
              <button 
                onClick={async () => { 
                  await stopScanner();
                  setIsScannerOpen(false); 
                  setIsKioskMode(false); 
                }} 
                className="w-full bg-white text-slate-900 font-black py-5 rounded-3xl transition-all flex items-center justify-center gap-2"
              >
                <ChevronLeft size={20} />
