  };

  if (!currentClass) {
    return (
      <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-300 pb-10">
        <header>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Seleção de Treino</h1>
