                      {lastScannedStudent.photo ? <img src={lastScannedStudent.photo} className="w-40 h-40 rounded-[60px] border-4 border-slate-50 shadow-lg object-cover" /> : <div className={`w-32 h-32 rounded-[40px] flex items-center justify-center text-white font-black text-4xl shadow-lg ${BELT_COLORS[lastScannedStudent.belt].split(' ')[0]}`}>{lastScannedStudent.name.charAt(0)}</div>}
                    </div>
