                    {graduationMilestone && <p className="text-amber-600 font-black text-2xl mb-6 flex items-center gap-2"><Star size={24} fill="currentColor" /> {graduationMilestone}</p>}
                    <p className="text-6xl font-black text-indigo-600 italic">OSS!</p>
