          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={toggleTheme}
              className="p-3 bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-indigo-400 rounded-2xl transition-all active:scale-90"
              title="Mudar Tema"
            >
              {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
            </button>
            <button 
              onClick={() => setIsLogoutModalOpen(true)}
              className="p-3 bg-red-50 dark:bg-red-950/30 text-red-600 dark:text-red-400 rounded-2xl transition-all active:scale-90 border border-red-100 dark:border-red-900/20"
              title="Sair"
            >
              <LogOut size={20} />
            </button>
          </div>
        </div>

        {/* Modal Logout */}
        {isLogoutModalOpen && (
          <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-900 w-full max-sm rounded-[40px] p-8 animate-in zoom-in duration-300 shadow-2xl text-center">
              <div className="bg-red-100 dark:bg-red-950/30 w-20 h-20 rounded-full flex items-center justify-center text-red-600 dark:text-red-400 mx-auto mb-6">
                <LogOut size={40} />
              </div>
              <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-2 tracking-tight">Encerrar Sessão?</h2>
              <p className="text-sm text-slate-500 dark:text-slate-400 font-medium mb-8 leading-relaxed">
