                  <button onClick={() => setIsMobileMenuOpen(false)} className="p-2 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-full"><X size={20} /></button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {MENU_ITEMS.map((item) => (
                    <Link key={item.to} to={item.to} onClick={() => setIsMobileMenuOpen(false)} className="flex flex-col items-center gap-3 p-5 rounded-3xl bg-slate-50 dark:bg-slate-800/50 hover:bg-indigo-50 dark:hover:bg-indigo-950/30 transition-all border border-transparent hover:border-indigo-100 dark:hover:border-indigo-900/50 group">
                      <div className="text-slate-400 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{item.icon}</div>
                      <span className="font-bold text-[11px] text-slate-600 dark:text-slate-300 uppercase tracking-widest text-center">{item.label}</span>
                    </Link>
                  ))}
                  {/* Item de Configurações no final do grid mobile para garantir que esteja lá */}
                  <Link to="/settings" onClick={() => setIsMobileMenuOpen(false)} className="flex flex-col items-center gap-3 p-5 rounded-3xl bg-indigo-50/50 dark:bg-indigo-900/20 hover:bg-indigo-100 dark:hover:bg-indigo-900/40 transition-all border border-indigo-100/50 dark:border-indigo-900/30 group">
                    <div className="text-indigo-600 dark:text-indigo-400 transition-colors"><Settings size={22} /></div>
                    <span className="font-bold text-[11px] text-indigo-700 dark:text-indigo-300 uppercase tracking-widest text-center">Configurações</span>
                  </Link>
                </div>
              </div>
            </div>
          </div>
