        <main className="flex-1 p-4 md:p-8">
          <Routes>
            <Route path="/" element={<DashboardView academy={academy} />} />
            <Route path="/templates" element={<TemplateView />} />
            <Route path="/attendance" element={<AttendanceView user={user} />} />
            <Route path="/finances" element={<FinancesView />} />
            <Route path="/students" element={<StudentsView />} />
            <Route path="/instructors" element={<InstructorsView />} />
            <Route path="/kimonos" element={<KimonoView />} />
            <Route path="/calendar" element={<CalendarView />} />
            <Route path="/chat" element={<ChatView user={user} />} />
            <Route path="/reports" element={<ReportsView />} />
            <Route path="/recycle-bin" element={<RecycleBinView />} />
            <Route path="/settings" element={<SettingsView academy={academy} onLogout={() => setIsLogoutModalOpen(true)} theme={theme} onToggleTheme={toggleTheme} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        {/* Dock (Mobile) */}
        <div className="md:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm z-[90]">
          <nav className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200/50 dark:border-slate-700/50 flex justify-between items-center h-20 px-4 rounded-[32px] shadow-2xl shadow-slate-900/20 transition-all">
            <BottomNavLink to="/" icon={<Home size={22} />} label="Início" />
            <BottomNavLink to="/finances" icon={<DollarSign size={22} />} label="Finanças" />
            <Link to="/attendance" className="relative -top-6 w-16 h-16 bg-indigo-600 text-white rounded-[24px] flex items-center justify-center shadow-xl shadow-indigo-600/40 hover:scale-110 active:scale-95 transition-all">
              <CheckCircle2 size={32} />
              <div className="absolute -bottom-1 w-2 h-2 bg-indigo-400 rounded-full animate-ping" />
            </Link>
            <BottomNavLink to="/students" icon={<Users size={22} />} label="Alunos" />
            <button onClick={() => setIsMobileMenuOpen(true)} className="flex flex-col items-center justify-center space-y-1 w-full h-full text-slate-400 dark:text-slate-500 transition-all">
              <LayoutGrid size={22} />
              <span className="text-[9px] font-black uppercase tracking-tighter">Menu</span>
            </button>
          </nav>
        </div>
      </div>
    </HashRouter>
  );
};

const BottomNavLink: React.FC<{ to: string; icon: React.ReactNode; label: string }> = ({ to, icon, label }) => {
  const location = useLocation();
  const isActive = location.pathname === to;
  return (
    <Link to={to} className={`flex flex-col items-center justify-center space-y-1 w-full h-full transition-all ${isActive ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-slate-400 dark:text-slate-500'}`}>
      <div className={isActive ? 'animate-in zoom-in duration-300' : ''}>{icon}</div>
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </Link>
  );
};

