          <div className="shrink-0">{theme === 'dark' ? <Sun size={20} className="text-amber-500" /> : <Moon size={20} />}</div>
          {!isCollapsed && <span className="font-bold text-sm">Tema {theme === 'dark' ? 'Claro' : 'Escuro'}</span>}
        </button>

        <button onClick={onLogout} className={`flex items-center text-slate-400 hover:text-red-400 transition-all h-12 rounded-xl hover:bg-slate-800/50 ${isCollapsed ? 'justify-center w-12 mx-auto' : 'px-4 gap-3'}`} title={isCollapsed ? "Sair" : ''}>
