import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useLocation } from 'react-router-dom';
import { 
  Users, 
  CheckCircle2, 
  BarChart3, 
  Settings, 
  Shirt,
  Search,
  ChevronRight,
  ChevronLeft,
  LogOut,
  Trophy,
