import RecycleBinView from './views/RecycleBinView';
import FinancesView from './views/FinancesView';

// Itens principais (Linha Inteira)
const MAIN_MENU = [
  { to: '/', icon: <Home size={20} />, label: 'Dashboard' },
  { to: '/attendance', icon: <CheckCircle2 size={20} />, label: 'Fazer Chamada' },
  { to: '/finances', icon: <DollarSign size={20} />, label: 'Financeiro' },
];

// Itens de Gestão (Grade de 2 Colunas)
const MANAGEMENT_MENU = [
  { to: '/students', icon: <Users size={18} />, label: 'Alunos' },
  { to: '/instructors', icon: <Award size={18} />, label: 'Mestres' },
  { to: '/templates', icon: <CalendarDays size={18} />, label: 'Turmas' },
  { to: '/calendar', icon: <Calendar size={18} />, label: 'Agenda' },
  { to: '/chat', icon: <MessageSquare size={18} />, label: 'Mural' },
  { to: '/kimonos', icon: <Shirt size={18} />, label: 'Quimonos' },
  { to: '/reports', icon: <BarChart3 size={18} />, label: 'Dados' },
  { to: '/recycle-bin', icon: <Trash2 size={18} />, label: 'Lixeira' },
];

const App: React.FC = () => {
  const [academy, setAcademy] = useState<Academy | null>(StorageService.getAcademy());
  const [user, setUser] = useState<User | null>(StorageService.getCurrentUser());
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLogoutModalOpen, setIsLogoutModalOpen] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>(StorageService.getTheme());

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    StorageService.saveTheme(theme);
  }, [theme]);

  const handleLogin = (loggedUser: User, currentAcademy: Academy) => {
    setUser(loggedUser);
    setAcademy(currentAcademy);
    StorageService.saveCurrentUser(loggedUser);
    StorageService.saveAcademy(currentAcademy);
  };

  const handleLogout = () => {
    StorageService.clear();
    setAcademy(null);
    setUser(null);
    setIsMobileMenuOpen(false);
    setIsLogoutModalOpen(false);
  };

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  if (!user || !academy) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className={`flex flex-col min-h-screen pb-24 md:pb-0 transition-all duration-300 dark:bg-slate-950 ${isSidebarCollapsed ? 'md:pl-20' : 'md:pl-64'}`}>
        <Sidebar 
          academy={academy} 
          onLogout={() => setIsLogoutModalOpen(true)} 
          isCollapsed={isSidebarCollapsed} 
          setIsCollapsed={setIsSidebarCollapsed}
          theme={theme}
          onToggleTheme={toggleTheme}
        />

        {/* Mobile Header */}
        <div className="md:hidden flex items-center justify-between px-6 py-5 bg-white dark:bg-slate-900 border-b dark:border-slate-800 sticky top-0 z-30 shadow-sm transition-colors">
          <div>
            <h1 className="text-xl font-black text-slate-800 dark:text-white tracking-tighter uppercase italic leading-none">CASA DO PAI</h1>
            <p className="text-[9px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-[0.2em] mt-1">{academy.name}</p>
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={toggleTheme}
              className="p-3 bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-indigo-400 rounded-2xl transition-all active:scale-90"
            >
              {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
            </button>
          </div>
        </div>

        {/* Modal Logout */}
        {isLogoutModalOpen && (
          <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-md z-[200] flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-900 w-full max-sm rounded-[40px] p-8 animate-in zoom-in duration-300 shadow-2xl text-center">
              <div className="bg-red-100 dark:bg-red-950/30 w-20 h-20 rounded-full flex items-center justify-center text-red-600 dark:text-red-400 mx-auto mb-6">
                <LogOut size={40} />
              </div>
              <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-2 tracking-tight">Encerrar Sessão?</h2>
              <p className="text-sm text-slate-500 dark:text-slate-400 font-medium mb-8 leading-relaxed">
                Deseja sair agora? Você terá que entrar novamente.
              </p>
              <div className="flex flex-col gap-3">
                <button onClick={handleLogout} className="w-full bg-red-600 text-white font-black py-5 rounded-3xl shadow-xl active:scale-95 transition-all">Sim, Sair</button>
                <button onClick={() => setIsLogoutModalOpen(false)} className="w-full bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 font-bold py-5 rounded-3xl transition-all">Cancelar</button>
              </div>
            </div>
          </div>
        )}

        {/* Bottom Menu (Mobile) */}
        {isMobileMenuOpen && (
          <div className="md:hidden fixed inset-0 z-[100] flex items-end">
            <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsMobileMenuOpen(false)} />
            <div className="relative w-full bg-white dark:bg-slate-900 rounded-t-[40px] shadow-2xl animate-in slide-in-from-bottom duration-500 p-8 flex flex-col max-h-[85vh]">
              <div className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mx-auto mb-8" />
              <div className="grid grid-cols-2 gap-4 overflow-y-auto">
                {[...MAIN_MENU, ...MANAGEMENT_MENU].map((item) => (
                  <Link key={item.to} to={item.to} onClick={() => setIsMobileMenuOpen(false)} className="flex flex-col items-center gap-3 p-5 rounded-3xl bg-slate-50 dark:bg-slate-800/50 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 transition-all border border-transparent group">
                    <div className="text-slate-400 group-hover:text-indigo-600 dark:group-hover:text-indigo-400">{item.icon}</div>
                    <span className="font-bold text-[10px] text-slate-600 dark:text-slate-300 uppercase tracking-widest">{item.label}</span>
                  </Link>
                ))}
                <Link to="/settings" onClick={() => setIsMobileMenuOpen(false)} className="flex flex-col items-center gap-3 p-5 rounded-3xl bg-indigo-50/50 dark:bg-indigo-900/20 col-span-2">
                  <div className="text-indigo-600 dark:text-indigo-400"><Settings size={22} /></div>
                  <span className="font-bold text-[10px] text-indigo-700 dark:text-indigo-300 uppercase tracking-widest">Configurações do Sistema</span>
                </Link>
              </div>
            </div>
          </div>
        )}

        <main className="flex-1 p-4 md:p-8">
          <Routes>
            <Route path="/" element={<DashboardView academy={academy} />} />
            <Route path="/templates" element={<TemplateView />} />
            <Route path="/attendance" element={<AttendanceView user={user} />} />
            <Route path="/finances" element={<FinancesView />} />
            <Route path="/students" element={<StudentsView />} />
            <Route path="/instructors" element={<InstructorsView />} />
            <Route path="/kimonos" element={<KimonoView />} />
            <Route path="/calendar" element={<CalendarView />} />
            <Route path="/chat" element={<ChatView user={user} />} />
            <Route path="/reports" element={<ReportsView />} />
            <Route path="/recycle-bin" element={<RecycleBinView />} />
            <Route path="/settings" element={<SettingsView academy={academy} onLogout={() => setIsLogoutModalOpen(true)} theme={theme} onToggleTheme={toggleTheme} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        {/* Dock (Mobile) */}
        <div className="md:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-[90%] max-w-sm z-[90]">
          <nav className="bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl border border-slate-200/50 dark:border-slate-700/50 flex justify-between items-center h-20 px-4 rounded-[32px] shadow-2xl">
            <BottomNavLink to="/" icon={<Home size={22} />} label="Início" />
            <BottomNavLink to="/finances" icon={<DollarSign size={22} />} label="Finanças" />
            <Link to="/attendance" className="relative -top-6 w-16 h-16 bg-indigo-600 text-white rounded-[24px] flex items-center justify-center shadow-xl shadow-indigo-600/40">
              <CheckCircle2 size={32} />
            </Link>
            <BottomNavLink to="/students" icon={<Users size={22} />} label="Alunos" />
            <button onClick={() => setIsMobileMenuOpen(true)} className="flex flex-col items-center justify-center space-y-1 w-full h-full text-slate-400">
              <LayoutGrid size={22} />
              <span className="text-[9px] font-black uppercase tracking-tighter">Menu</span>
            </button>
          </nav>
        </div>
      </div>
    </HashRouter>
  );
};

const BottomNavLink: React.FC<{ to: string; icon: React.ReactNode; label: string }> = ({ to, icon, label }) => {
  const location = useLocation();
  const isActive = location.pathname === to;
  return (
    <Link to={to} className={`flex flex-col items-center justify-center space-y-1 w-full h-full transition-all ${isActive ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-slate-400'}`}>
      {icon}
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </Link>
  );
};

